class Solution:
    def minFlips(self, grid):
        m, n = len(grid), len(grid[0])
        if m * n <= 16:
            cells = [(i, j) for i in range(m) for j in range(n)]
            total_cells = len(cells)
            best = None
            for mask in range(1 << total_cells):
                if best is not None and bin(mask).count('1') >= best:
                    continue
                g = [row[:] for row in grid]
                flips = 0
                for idx, (i, j) in enumerate(cells):
                    if (mask >> idx) & 1:
                        g[i][j] ^= 1
                        flips += 1
                ok = True
                for i in range(m):
                    for j in range(n // 2):
                        if g[i][j] != g[i][n - 1 - j]:
                            ok = False
                            break
                    if not ok:
                        break
                if ok:
                    for j in range(n):
                        for i in range(m // 2):
                            if g[i][j] != g[m - 1 - i][j]:
                                ok = False
                                break
                        if not ok:
                            break
                if ok:
                    total_ones = sum(sum(row) for row in g)
                    if total_ones % 4 == 0:
                        if best is None or flips < best:
                            best = flips
            return best
        cost = 0
        for i in range(m // 2):
            for j in range(n // 2):
                ones = (grid[i][j] + grid[i][n - 1 - j] + grid[m - 1 - i][j] + grid[m - 1 - i][n - 1 - j])
                cost += min(ones, 4 - ones)
        forced_ones = 0
        flex_two = 0
        matched_pair_exists = False
        if m % 2 == 1:
            mid = m // 2
            for j in range(n // 2):
                a, b = grid[mid][j], grid[mid][n - 1 - j]
                if a == b:
                    forced_ones += 2 * a
                    matched_pair_exists = True
                else:
                    cost += 1
                    flex_two += 1
        if n % 2 == 1:
            mid = n // 2
            for i in range(m // 2):
                a, b = grid[i][mid], grid[m - 1 - i][mid]
                if a == b:
                    forced_ones += 2 * a
                    matched_pair_exists = True
                else:
                    cost += 1
                    flex_two += 1
        center_exists = (m % 2 == 1) and (n % 2 == 1)
        center_val = grid[m // 2][n // 2] if center_exists else 0
        forced_ones += center_val
        base = forced_ones % 4
        options = [(0, 0)]
        if flex_two >= 1:
            options = options + [(c, s + 2) for c, s in options]
        if center_exists:
            c_shift = 1 - 2 * center_val
            options = options + [(c + 1, s + c_shift) for c, s in options]
        if matched_pair_exists:
            options = options + [(c + 2, s + 2) for c, s in options]
        best_extra = min(c for c, s in options if (base + s) % 4 == 0)
        return cost + best_extra

