var minFlips = function(grid) {
    const m = grid.length, n = grid[0].length;
    let cost = 0;
    for (let i = 0; i < Math.floor(m / 2); i++) {
        for (let j = 0; j < Math.floor(n / 2); j++) {
            const ones = grid[i][j] + grid[i][n - 1 - j] + grid[m - 1 - i][j] + grid[m - 1 - i][n - 1 - j];
            cost += Math.min(ones, 4 - ones);
        }
    }
    let forcedOnes = 0;
    let flexTwo = 0;
    let matchedPairExists = false;
    if (m % 2 === 1) {
        const mid = Math.floor(m / 2);
        for (let j = 0; j < Math.floor(n / 2); j++) {
            const a = grid[mid][j], b = grid[mid][n - 1 - j];
            if (a === b) {
                forcedOnes += 2 * a;
                matchedPairExists = true;
            } else {
                cost += 1;
                flexTwo += 1;
            }
        }
    }
    if (n % 2 === 1) {
        const mid = Math.floor(n / 2);
        for (let i = 0; i < Math.floor(m / 2); i++) {
            const a = grid[i][mid], b = grid[m - 1 - i][mid];
            if (a === b) {
                forcedOnes += 2 * a;
                matchedPairExists = true;
            } else {
                cost += 1;
                flexTwo += 1;
            }
        }
    }
    const centerExists = (m % 2 === 1) && (n % 2 === 1);
    const centerVal = centerExists ? grid[Math.floor(m / 2)][Math.floor(n / 2)] : 0;
    forcedOnes += centerVal;
    const base = forcedOnes % 4;
    let options = [[0, 0]];
    if (flexTwo >= 1) {
        options = options.concat(options.map(([c, s]) => [c, s + 2]));
    }
    if (centerExists) {
        const cShift = 1 - 2 * centerVal;
        options = options.concat(options.map(([c, s]) => [c + 1, s + cShift]));
    }
    if (matchedPairExists) {
        options = options.concat(options.map(([c, s]) => [c + 2, s + 2]));
    }
    let bestExtra = Infinity;
    for (const [c, s] of options) {
        if (((base + s) % 4 + 4) % 4 === 0) {
            bestExtra = Math.min(bestExtra, c);
        }
    }
    return cost + bestExtra;
};
